proof_block:
// Re-assert every ensures conjunct for both post-states so the two parallel
// `forall` instantiations (one per run) share triggers, then close the
// sequence equality on endpoint_descriptors@ via Seq extensionality (=~=).

// Domain equalities (post1 / post2 each pinned to pre_self_).
assert(post1_self_.container_dom() == pre_self_.container_dom());
assert(post2_self_.container_dom() == pre_self_.container_dom());
assert(post1_self_.proc_dom() == pre_self_.proc_dom());
assert(post2_self_.proc_dom() == pre_self_.proc_dom());
assert(post1_self_.thread_dom() == pre_self_.thread_dom());
assert(post2_self_.thread_dom() == pre_self_.thread_dom());

// ProcMan-level relational invariants (each typically a `forall` — re-state for both runs).
assert(containers_tree_unchanged(pre_self_.proc_man, post1_self_.proc_man));
assert(containers_tree_unchanged(pre_self_.proc_man, post2_self_.proc_man));
assert(containers_owned_proc_unchanged(pre_self_.proc_man, post1_self_.proc_man));
assert(containers_owned_proc_unchanged(pre_self_.proc_man, post2_self_.proc_man));
assert(processes_unchanged(pre_self_.proc_man, post1_self_.proc_man));
assert(processes_unchanged(pre_self_.proc_man, post2_self_.proc_man));
assert(threads_unchanged_except(pre_self_.proc_man, post1_self_.proc_man, set![thread_ptr]));
assert(threads_unchanged_except(pre_self_.proc_man, post2_self_.proc_man, set![thread_ptr]));

// The sequence-equality ensures — main trigger gap. Both posts equal the same
// RHS, so by transitivity (lifted through Seq ext-equality) they agree.
assert(post1_self_.get_thread(thread_ptr).endpoint_descriptors@
    =~= pre_self_.get_thread(thread_ptr).endpoint_descriptors@.update(edp_idx as int, None));
assert(post2_self_.get_thread(thread_ptr).endpoint_descriptors@
    =~= pre_self_.get_thread(thread_ptr).endpoint_descriptors@.update(edp_idx as int, None));
assert(post1_self_.get_thread(thread_ptr).endpoint_descriptors@
    =~= post2_self_.get_thread(thread_ptr).endpoint_descriptors@);

// Per-field equalities on get_thread(thread_ptr): state, blocking_endpoint_index, owning_proc.
assert(post1_self_.get_thread(thread_ptr).state == pre_self_.get_thread(thread_ptr).state);
assert(post2_self_.get_thread(thread_ptr).state == pre_self_.get_thread(thread_ptr).state);
assert(post1_self_.get_thread(thread_ptr).state == post2_self_.get_thread(thread_ptr).state);
assert(post1_self_.get_thread(thread_ptr).blocking_endpoint_index
    == pre_self_.get_thread(thread_ptr).blocking_endpoint_index);
assert(post2_self_.get_thread(thread_ptr).blocking_endpoint_index
    == pre_self_.get_thread(thread_ptr).blocking_endpoint_index);
assert(post1_self_.get_thread(thread_ptr).blocking_endpoint_index
    == post2_self_.get_thread(thread_ptr).blocking_endpoint_index);
assert(post1_self_.get_thread(thread_ptr).owning_proc == pre_self_.get_thread(thread_ptr).owning_proc);
assert(post2_self_.get_thread(thread_ptr).owning_proc == pre_self_.get_thread(thread_ptr).owning_proc);
assert(post1_self_.get_thread(thread_ptr).owning_proc == post2_self_.get_thread(thread_ptr).owning_proc);
